  ) |>
  gt::tab_style(
    style = list(gt::cell_fill(color = "#a5ffa5")),
    locations = gt::cells_body(columns = 5, rows = c(3, 8))
  ) |>
  gt::tab_style(
    style = list(gt::cell_fill(color = "#a5ffa5")),
    locations = gt::cells_body(columns = 6, rows = c(1, 6))
  ) |>
